#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct Node {
    int data;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new tree node
Node* newNode(int data) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->data = data;
    node->left = node->right = NULL;
    return node;
}

// Function to reconstruct the binary tree from inorder and postorder traversals
Node* buildTree(int* inorder, int* postorder, int start, int end, int* postIndex) {
    if (start > end) return NULL;

    Node* node = newNode(postorder[*postIndex]);
    (*postIndex)--;

    if (start == end) return node;

    int index = start;
    while (inorder[index] != node->data) index++;

    node->right = buildTree(inorder, postorder, index + 1, end, postIndex);
    node->left = buildTree(inorder, postorder, start, index - 1, postIndex);

    return node;
}

// Function to perform preorder traversal of the tree
void preorder(Node* node) {
    if (node == NULL) return;

    printf("%d ", node->data);
    preorder(node->left);
    preorder(node->right);
}

int main() {
    int T;
    scanf("%d", &T);

    while (T--) {
        int N;
        scanf("%d", &N);

        int* inorder = (int*)malloc(N * sizeof(int));
        int* postorder = (int*)malloc(N * sizeof(int));

        for (int i = 0; i < N; i++) scanf("%d", &inorder[i]);
        for (int i = 0; i < N; i++) scanf("%d", &postorder[i]);

        int postIndex = N - 1;
        Node* root = buildTree(inorder, postorder, 0, N - 1, &postIndex);

        preorder(root);
        printf("\n");
    }

    return 0;
}

