import java.util.Scanner;

public class Main {
    // Define the structure for a tree node
    static class Node {
        int data;
        Node left;
        Node right;

        Node(int data) {
            this.data = data;
            this.left = null;
            this.right = null;
        }
    }

    // Function to reconstruct the binary tree from inorder and postorder traversals
    static Node buildTree(int[] inorder, int[] postorder, int start, int end, int[] postIndex) {
        if (start > end) return null;

        Node node = new Node(postorder[postIndex[0]]);
        postIndex[0]--;

        if (start == end) return node;

        int index = start;
        while (inorder[index] != node.data) index++;

        node.right = buildTree(inorder, postorder, index + 1, end, postIndex);
        node.left = buildTree(inorder, postorder, start, index - 1, postIndex);

        return node;
    }

    // Function to perform preorder traversal of the tree
    static void preorder(Node node) {
        if (node == null) return;

        System.out.print(node.data + " ");
        preorder(node.left);
        preorder(node.right);
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();

        while (T-- > 0) {
            int N = scanner.nextInt();

            int[] inorder = new int[N];
            int[] postorder = new int[N];

            for (int i = 0; i < N; i++) inorder[i] = scanner.nextInt();
            for (int i = 0; i < N; i++) postorder[i] = scanner.nextInt();

            int[] postIndex = new int[] { N - 1 };
            Node root = buildTree(inorder, postorder, 0, N - 1, postIndex);

            preorder(root);
            System.out.println();
        }
    }
}

